// The keyword is `type`, not `interface`
type UserId = number;
type Email = string;

// At runtime these are just number and string
// TypeScript treats them as structurally equivalent to their bases
const id: UserId = 42;
const email: Email = "alice@example.com";

// You can alias any expression — not only primitives
type Point = { x: number; y: number };
type OrNull<T> = T | null;
type StringOrNumber = string | number;

// Semantic aliases — structurally identical to the base type
type Kg     = number;
type Metres = number;

function applyForce(mass: Kg, distance: Metres): number {
  return mass * distance;
}
// No compile error — Kg and Metres are both `number`
applyForce(10, 5);   // fine
applyForce(5, 10);   // also fine — order doesn't matter at type level

// Branded types — inject a phantom property to differentiate
type KgBranded     = number & { readonly _brand: "Kg" };
type MetresBranded = number & { readonly _brand: "Metres" };

function kg(n: number): KgBranded     { return n as KgBranded; }
function metres(n: number): MetresBranded { return n as MetresBranded; }

function applyForceSafe(mass: KgBranded, dist: MetresBranded): number {
  return mass * dist;
}
applyForceSafe(kg(10), metres(5));    // OK
// applyForceSafe(metres(5), kg(10)); // Error — brands mismatch

// Object alias
type User = {
  id: number;
  name: string;
  email: string;
  createdAt: Date;
};

// Intersection — combine two shapes
type Timestamped = { createdAt: Date; updatedAt: Date };
type UserWithAudit = User & Timestamped;

// Inline optional fields — same as interface optional
type Config = {
  host: string;
  port?: number;         // optional
  readonly secret: string; // read-only
};

// Type alias referencing another alias
type ApiUser = Omit<User, "createdAt">;
// { id: number; name: string; email: string }

// Union: a value is ONE of these shapes
type Result<T> =
  | { ok: true;  value: T }
  | { ok: false; error: string };

function divide(a: number, b: number): Result<number> {
  if (b === 0) return { ok: false, error: "Division by zero" };
  return { ok: true, value: a / b };
}

const r = divide(10, 2);
if (r.ok) {
  console.log(r.value); // narrowed: value exists
} else {
  console.error(r.error); // narrowed: error exists
}

// Intersection: a value satisfies ALL of these shapes
type WithId   = { id: number };
type WithName = { name: string };
type Entity   = WithId & WithName;

const entity: Entity = { id: 1, name: "Alice" };

// Reusable HTTP response alias
type ApiResponse<T> =
  | { status: "success"; data: T }
  | { status: "error";   message: string; code: number };

// Simple generic wrapper
type Maybe<T> = T | null | undefined;

function getUser(id: number): Maybe<User> {
  return users.find(u => u.id === id) ?? null;
}

// Pair and triple
type Pair<A, B = A>  = [A, B];       // B defaults to A
type Triple<A, B, C> = [A, B, C];

const coords: Pair<number> = [10, 20];

// Constrained type parameter
type Serialisable<T extends object> = T & { toJSON(): string };

// Promise alias (standard lib uses this pattern)
type AsyncResult<T> = Promise<Result<T>>;

// Angular HTTP alias — saves repeating Observable<…> everywhere
import { Observable } from "rxjs";
type ApiStream<T> = Observable<ApiResponse<T>>;

// Usage in a service
@Injectable({ providedIn: "root" })
class UserService {
  constructor(private http: HttpClient) {}

  getUsers(): ApiStream<User[]> {
    return this.http.get<User[]>("/api/users").pipe(
      map(data => ({ status: "success" as const, data })),
      catchError(err => of({ status: "error" as const, message: err.message, code: err.status }))
    );
  }
}

// Standard library Partial and Required — both are type aliases
type Partial<T>  = { [K in keyof T]?: T[K] };
type Required<T> = { [K in keyof T]-?: T[K] }; // -? removes optionality

// Read-only everywhere
type DeepReadonly<T> = {
  readonly [K in keyof T]: T[K] extends object ? DeepReadonly<T[K]> : T[K];
};

// Pick a subset of keys
type Pick<T, K extends keyof T> = { [P in K]: T[P] };

// Exclude specific keys
type Omit<T, K extends keyof T> = Pick<T, Exclude<keyof T, K>>;

// Angular form alias — FormGroup mirrors an object type
import { FormControl } from "@angular/forms";
type FormControls<T> = { [K in keyof T]: FormControl<T[K]> };

interface LoginForm {
  email: string;
  password: string;
}
// FormControls<LoginForm> = { email: FormControl<string>; password: FormControl<string> }
const controls: FormControls<LoginForm> = {
  email:    new FormControl("", { nonNullable: true }),
  password: new FormControl("", { nonNullable: true }),
};

// Conditional type — basic form
type IsArray<T> = T extends unknown[] ? true : false;

type A = IsArray<string[]>; // true
type B = IsArray<string>;   // false

// Infer inside conditional — extract the element type
type ElementOf<T> = T extends (infer E)[] ? E : never;

type Elem = ElementOf<User[]>; // User
type None = ElementOf<string>; // never

// Unwrap a Promise
type Awaited<T> = T extends Promise<infer U> ? Awaited<U> : T;
// Handles nested Promises: Awaited<Promise<Promise<number>>> = number

// Flatten one level of union from a function
type ReturnType<T extends (...args: never[]) => unknown> =
  T extends (...args: never[]) => infer R ? R : never;

// Angular: extract the resolved model from a resolver
import { ResolveFn } from "@angular/router";
type ResolvedModel<F> = F extends ResolveFn<infer M> ? M : never;

type UserResolver = ResolveFn<User>;
type Model = ResolvedModel<UserResolver>; // User

// JSON value — self-referential union
type JsonValue =
  | string
  | number
  | boolean
  | null
  | JsonValue[]
  | { [key: string]: JsonValue };

// Usage: safe JSON storage without `any`
function safeStringify(value: JsonValue): string {
  return JSON.stringify(value);
}

// Binary tree
type BinaryTree<T> =
  | null
  | { value: T; left: BinaryTree<T>; right: BinaryTree<T> };

function depth<T>(tree: BinaryTree<T>): number {
  if (tree === null) return 0;
  return 1 + Math.max(depth(tree.left), depth(tree.right));
}

// Angular: recursive route config type (simplified)
type RouteNode = {
  path: string;
  component?: unknown;
  children?: RouteNode[];
};

// All of these are defined as type aliases in lib.es5.d.ts

// Partial<T> — make every property optional
type Partial<T> = { [P in keyof T]?: T[P] };

// Required<T> — make every property required
type Required<T> = { [P in keyof T]-?: T[P] };

// Readonly<T> — make every property read-only
type Readonly<T> = { readonly [P in keyof T]: T[P] };

// Record<K, V> — object with keys K and values V
type Record<K extends keyof any, T> = { [P in K]: T };

// Pick<T, K> — keep only listed keys
type Pick<T, K extends keyof T> = { [P in K]: T[P] };

// Omit<T, K> — remove listed keys
type Omit<T, K extends keyof any> = Pick<T, Exclude<keyof T, K>>;

// Exclude<T, U> — remove members of U from union T
type Exclude<T, U> = T extends U ? never : T;

// Extract<T, U> — keep only members assignable to U
type Extract<T, U> = T extends U ? T : never;

// NonNullable<T> — remove null and undefined
type NonNullable<T> = T & {};

// ReturnType<F> — extract return type of function
type ReturnType<T extends (...args: never[]) => unknown> =
  T extends (...args: never[]) => infer R ? R : never;

// Angular component input type pattern
import { InputSignal } from "@angular/core";
type InputValue<T extends InputSignal<unknown>> =
  T extends InputSignal<infer V> ? V : never;

// HTTP resource aliases
import { HttpClient } from "@angular/common/http";
import { Observable } from "rxjs";

type UserList   = Observable<User[]>;
type SingleUser = Observable<User | null>;

// Discriminated union state — common in NgRx-free state management
type FetchState<T> =
  | { status: "idle" }
  | { status: "loading" }
  | { status: "success"; data: T }
  | { status: "error";   message: string };

@Component({ selector: "app-users", template: "" })
class UsersComponent {
  state: FetchState<User[]> = { status: "idle" };

  load() {
    this.state = { status: "loading" };
    this.http.get<User[]>("/api/users").subscribe({
      next:  data  => (this.state = { status: "success", data }),
      error: err   => (this.state = { status: "error", message: err.message }),
    });
  }

  constructor(private http: HttpClient) {}
}

// Signal-based component input alias
import { InputSignal, input } from "@angular/core";

type StringInput    = InputSignal<string>;
type OptionalInput  = InputSignal<string | undefined>;

@Component({ selector: "app-badge", template: "{{ label() }}" })
class BadgeComponent {
  label: StringInput = input.required<string>();
}

// Alias for a simple callback
type Callback<T> = (value: T) => void;
type AsyncCallback<T> = (value: T) => Promise<void>;

// Alias for a predicate function
type Predicate<T> = (item: T) => boolean;

function filter<T>(items: T[], pred: Predicate<T>): T[] {
  return items.filter(pred);
}

const adults = filter(users, u => u.age >= 18);

// Alias for an event handler
type DomHandler<E extends Event = Event> = (event: E) => void;
type ClickHandler  = DomHandler<MouseEvent>;
type KeyHandler    = DomHandler<KeyboardEvent>;

// Angular output alias
import { EventEmitter } from "@angular/core";
type TypedEmitter<T> = EventEmitter<T>;

// Function overload alias — combine multiple call signatures
type Formatter = {
  (value: number, decimals: number): string;
  (value: string): string;
};

// Higher-order function alias
type Middleware<T> = (value: T, next: (v: T) => T) => T;

function compose<T>(...fns: Middleware<T>[]): (v: T) => T {
  return (v) => fns.reduceRight((acc, fn) => fn(acc, x => x), v);
}

// CSS class naming — combine modifiers and components
type Variant  = "primary" | "secondary" | "danger";
type Size     = "sm" | "md" | "lg";
type BtnClass = `btn-${Variant}-${Size}`;
// "btn-primary-sm" | "btn-primary-md" | ... 9 members

// Angular event naming
type LifecycleHook = "Init" | "Destroy" | "Changes" | "Check";
type HookName = `ng${LifecycleHook}`;
// "ngInit" | "ngDestroy" | "ngChanges" | "ngCheck"

// API route builder
type ApiVersion = "v1" | "v2";
type Resource   = "users" | "posts" | "comments";
type ApiRoute   = `/api/${ApiVersion}/${Resource}`;
// "/api/v1/users" | "/api/v1/posts" | ... 6 routes

// Map-key accessor from object keys
type EventKey<T extends object> = keyof T extends string
  ? `on${Capitalize<keyof T & string>}`
  : never;

interface UserEvents {
  created: User;
  updated: User;
  deleted: number;
}
type UserEventKeys = EventKey<UserEvents>;
// "onCreated" | "onUpdated" | "onDeleted"

// Clean intersection of non-overlapping shapes
type Clickable = { onClick(): void };
type Focusable = { onFocus(): void; onBlur(): void };
type Interactive = Clickable & Focusable;
// { onClick(): void; onFocus(): void; onBlur(): void }

// PITFALL: overlapping property with incompatible types
type A = { value: string };
type B = { value: number };
type AB = A & B;
// AB.value: string & number = never
// A variable of type AB can never be assigned — avoid this

// PITFALL: nested objects are NOT merged — they intersect at the type level
type Config1 = { db: { host: string } };
type Config2 = { db: { port: number } };
type FullConfig = Config1 & Config2;
// FullConfig.db: { host: string } & { port: number }
// = { host: string; port: number } — type works
// But at runtime: { ...config1, ...config2 } gives you config2.db only!
// You must merge deeply at runtime:
function mergeDeep<T>(a: T, b: Partial<T>): T {
  // ...implementation
  return { ...a, ...b };
}

// Angular mixin pattern — intersection of class statics
type Constructor<T = {}> = new (...args: any[]) => T;
type Serialisable = { serialize(): string };

function WithSerialize<TBase extends Constructor>(Base: TBase) {
  return class extends Base implements Serialisable {
    serialize(): string { return JSON.stringify(this); }
  };
}

// Build up from small pieces
type Id      = number;
type ISODate = string;
type Url     = string;

type BaseEntity = {
  id: Id;
  createdAt: ISODate;
  updatedAt: ISODate;
};

type Media = {
  url: Url;
  mimeType: string;
  sizeBytes: number;
};

type Article = BaseEntity & {
  title: string;
  body: string;
  coverImage: Media;
  tags: string[];
};

// Derive editing shape from the full type
type ArticleInput = Omit<Article, keyof BaseEntity>;
// { title: string; body: string; coverImage: Media; tags: string[] }

// Derive a list-view projection
type ArticleListItem = Pick<Article, "id" | "title" | "tags" | "createdAt">;

// HTTP layer uses derived types
type CreateArticleBody = ArticleInput;
type UpdateArticleBody = Partial<ArticleInput>;

// Angular resolver returns the full article
import { ResolveFn } from "@angular/router";
type ArticleResolver = ResolveFn<Article>;
